			missingExternalInputs: string[];
		};
	};
};

type PlannedChange = {
	kind: string;
	target: string;
	action: string;
	reason: string;
	requiresUserConfirmation: boolean;
	wouldWrite: boolean;
};

type AppliedChange = {
	key: string;
	target: string;
	action: string;
	wrote: boolean;
};

type Report = {
	ok: boolean;
	mode: "dry-run" | "apply";
	phase: "configure-local";
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	appliedChanges?: AppliedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	error?: string;
};

const GENERATED_SECRET_KEYS = [
	"ROOT_PASSWORD",
	"AUTH_SECRET",
	"CRON_SECRET",
	"MEDIATOR_SECRET",
] as const;

const EXTERNAL_INPUT_KEYS = [
	"TURSO_DATABASE_URL",
	"TURSO_AUTH_TOKEN",
	"GITHUB_TOKEN",
	"VERCEL_TOKEN",
	"VERCEL_TEAM_ID",
	"VERCEL_PROJECT_ID",
	"INITIAL_CHATGPT_AUTH_JSON",
] as const;

function run(command: string, args: string[]) {
	return spawnSync(command, args, { encoding: "utf8" });
}

function parseMode(argv: string[]) {
	const flags = argv.slice(2).filter((flag) => flag !== "--");
	if (flags.length === 0) {
		return "dry-run" as const;
	}

	if (flags.length === 1 && flags[0] === "--dry-run") {
		return "dry-run" as const;
	}

	if (
		flags.length === 2 &&
		flags.includes("--apply") &&
		flags.includes("--yes")
